<?php
declare(strict_types=1);
require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';
$portal=portalEstudianteCabecera('Calificaciones','calificaciones','Notas y retroalimentación registradas por tus docentes.');$pdo=obtenerConexion();
$q=$pdo->prepare("SELECT e.id,c.id contenido_id,c.titulo,a.nombre capacitacion,e.intento,e.estado,e.nota,e.retroalimentacion,e.revisado_at,e.enviado_at FROM entregas_contenido e JOIN contenidos c ON c.id=e.contenido_id JOIN asignaturas a ON a.id=e.asignatura_id WHERE e.estudiante_id=:u ORDER BY e.enviado_at DESC,e.id DESC");$q->execute(['u'=>$portal['perfil']['id']]);$filas=$q->fetchAll();$notas=array_values(array_filter($filas,static fn($f)=>$f['nota']!==null));$promedio=$notas?array_sum(array_map(static fn($f)=>(float)$f['nota'],$notas))/count($notas):null;
?>
<div class="row g-3 mb-4"><div class="col-md-4"><div class="aula-stat p-3"><span class="text-muted">Promedio de entregas calificadas</span><strong class="d-block display-6 mt-2"><?=$promedio!==null?number_format($promedio,2).'/10':'—'?></strong></div></div><div class="col-md-4"><div class="aula-stat p-3"><span class="text-muted">Aprobadas</span><strong class="d-block display-6 mt-2"><?=count(array_filter($filas,static fn($f)=>$f['estado']==='aprobada'))?></strong></div></div><div class="col-md-4"><div class="aula-stat p-3"><span class="text-muted">En revisión</span><strong class="d-block display-6 mt-2"><?=count(array_filter($filas,static fn($f)=>in_array($f['estado'],['enviada','en_revision'],true)))?></strong></div></div></div>
<div class="card"><div class="card-body"><div class="table-responsive"><table class="table align-middle aula-responsive-table"><thead><tr><th>Actividad</th><th>Capacitación</th><th>Intento</th><th>Estado</th><th>Nota</th><th>Retroalimentación</th></tr></thead><tbody><?php foreach($filas as$f):?><tr><td data-label="Actividad"><a href="<?=atenea_url('src/estudiantes/contenido.php?id='.(int)$f['contenido_id'])?>"><?=atenea_e($f['titulo'])?></a></td><td data-label="Capacitación"><?=atenea_e($f['capacitacion'])?></td><td data-label="Intento"><?=(int)$f['intento']?></td><td data-label="Estado"><?=atenea_e(ucfirst(str_replace('_',' ',$f['estado'])))?></td><td data-label="Nota"><?=$f['nota']!==null?number_format((float)$f['nota'],2).'/10':'Pendiente'?></td><td data-label="Retroalimentación"><?=atenea_e((string)($f['retroalimentacion']?:'Sin retroalimentación todavía'))?></td></tr><?php endforeach;?><?php if(!$filas):?><tr><td colspan="6"><div class="aula-empty"><i class="bi bi-clipboard-data"></i><p class="mt-2 mb-0">Aún no tienes entregas o calificaciones registradas.</p></div></td></tr><?php endif;?></tbody></table></div></div></div><?php portalEstudiantePie();
